+ pLeft + 'px',\n      'padding-right:' + pRight + 'px',\n      'width:' + chart.chartWidth + 'px',\n      'box-sizing:border-box',\n      'pointer-events:none'\n    ].join(';');\n\n    for (var j = 0; j < nGroups; j++) {\n      var cell = document.createElement('div');\n      cell.textContent = groups.KV[j];\n      cell.style.cssText = [\n        'flex:' + groups.n_cols[j],\n        'text-align:center',\n        'font-size:12px',\n        'font-family:Cambria,serif',\n        'font-weight:bold',\n        'color:#333333',\n        'border-top:2px solid #555555',\n        'padding-top:4px'\n      ].join(';');\n      row.appendChild(cell);\n    }\n    el.appendChild(row);\n  }\n\n  function updateChart(loaiPin) {\n    var d     = getFilteredData(loaiPin);\n    var chart = getChart();\n    if (!chart) return;\n\n    chart.xAxis[0].setCategories(d.cats, false);\n    chart.series[0].setData(makeColoredData(d.vals), false);\n    chart.redraw();\n\n    setTimeout(function() {\n      drawKVLabels(chart, d.kv_groups, d.n_total, el);\n    }, 300);\n  }\n\n  function init() {\n    var chart = getChart();\n    if (!chart || !chart.plotWidth) { setTimeout(init, 300); return; }\n\n    // Vẽ KV labels mặc định\n    drawKVLabels(chart, defaultData.kv_groups, defaultData.n_total, el);\n\n    // Gắn sự kiện filter\n    var wrapper = el.closest('.filter-chart-block-du');\n    var sel = wrapper\n      ? wrapper.querySelector('select')\n      : document.getElementById('filter_loai_pin_du');\n\n    if (sel) {\n      updateChart(sel.value);\n      sel.addEventListener('change', function() {\n        updateChart(this.value);\n      });\n    }\n  }\n\n  setTimeout(init, 300);\n  setTimeout(init, 800);\n  setTimeout(init, 1500);\n}\n","data":null}]}}</script>
